def calculate_mirr():
    cfs = [-12000, 5800, 6500, 6200, 5100, -4300]
    rate = 0.10

    # Discounting approach: discount negative cash flows to time 0
    mod_cfs = [0] * len(cfs)
    for i, cf in enumerate(cfs):
        if cf < 0:
            mod_cfs[0] += cf / ((1 + rate) ** i)
        else:
            mod_cfs[i] += cf

    # Calculate IRR of the modified cash flows using bisection method
    low = 0.0
    high = 1.0
    for _ in range(100):
        mid = (low + high) / 2
        npv = sum(c / ((1 + mid) ** i) for i, c in enumerate(mod_cfs))
        if npv > 0:
            low = mid
        else:
            high = mid

    print(f"{mid:.4f}")

